sql:
SELECT app_name, rating AS average_rating
FROM apps
ORDER BY rating DESC;

SELECT COUNT(app_id) 
FROM apps 
WHERE type = 'Paid' AND content_rating_id = 18;

external_knowledge:
- 'creators behind apps' refers to the developer of each app;
- 'popularity ratings' are represented by the average rating of the app;
- 'types of categories' are the name of the category to which an app belongs.

- 'maestros of the digital realm' refers to developers; 
- 'crafted instruments' refers to developed apps;
- 'earned a place among the stars' refers to achieving high ratings, specifically greater than 4.5;

sql:
SELECT COUNT(*)
FROM app_installs
WHERE app_id = 'your_app_id';

SELECT app_name, rating
FROM apps
WHERE app_id = 0;

SELECT apps.app_id, apps.app_name, categories.category_name, apps.rating, apps.reviews
FROM apps
JOIN categories ON apps.category_id = categories.category_id;

SELECT app_name, rating AS average_rating
FROM apps
WHERE installs > 5000 AND rating > 4.0;

SELECT app_name
FROM apps
WHERE reviews > (SELECT AVG(reviews) FROM apps);

SELECT app_id, COUNT(*) AS num_installs
FROM app_installs
GROUP BY app_id;
